/**
 * Helper class for a Min Priority Queue implementation.
 * Stores elements [time, negated_color, r, c]
 * Comparison: Smallest time first. If times are equal, largest color first (smallest negated_color).
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    _getParentIndex(i) { return Math.floor((i - 1) / 2); }
    _getLeftChildIndex(i) { return 2 * i + 1; }
    _getRightChildIndex(i) { return 2 * i + 2; }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    // Comparison function: returns true if element at index i has higher priority (smaller value) than element at index j
    _hasHigherPriority(i, j) {
        const [t_i, nc_i] = this.heap[i];
        const [t_j, nc_j] = this.heap[j];

        if (t_i !== t_j) {
            return t_i < t_j; // Min time wins
        }
        // If times are equal, larger color (smaller negated_color) wins
        return nc_i < nc_j;
    }

    enqueue(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }

    _bubbleUp(index) {
        let currentIndex = index;
        let parentIndex = this._getParentIndex(currentIndex);

        while (currentIndex > 0 && this._hasHigherPriority(currentIndex, parentIndex)) {
            this._swap(currentIndex, parentIndex);
            currentIndex = parentIndex;
            parentIndex = this._getParentIndex(currentIndex);
        }
    }

    _bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let left = this._getLeftChildIndex(currentIndex);
            let right = this._getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            // Compare with left child
            if (left <= lastIndex && this._hasHigherPriority(left, smallest)) {
                smallest = left;
            }

            // Compare with right child
            if (right <= lastIndex && this._hasHigherPriority(right, smallest)) {
                smallest = right;
            }

            if (smallest !== currentIndex) {
                this._swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
}


function solve(n, m, sources) {
    // Distance matrix: Stores the minimum time required to reach (r, c)
    // Initialize to Infinity
    const dist = Array(n).fill(0).map(() => Array(m).fill(Infinity));

    // Color grid: Stores the final color assigned to (r, c)
    const colorGrid = Array(n).fill(0).map(() => Array(m).fill(0));

    // Priority Queue: Stores [time, negated_color, r, c]
    const pq = new MinPriorityQueue();

    // 1. Initialization from sources
    for (const source of sources) {
        const [r, c, color] = source;

        // Since sources are guaranteed unique, we just initialize them
        dist[r][c] = 0;
        colorGrid[r][c] = color;
        // Push [time=0, negated_color=-color, r, c]
        pq.enqueue([0, -color, r, c]);
    }

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    // 2. Dijkstra/Modified BFS
    while (!pq.isEmpty()) {
        const [time, negColor, r, c] = pq.dequeue();
        const currentColor = -negColor;

        // If this is a stale entry (we found a faster path already), skip it.
        // Note: Due to color updates at the same time T, we must also check if the dequeued color is still the highest color recorded for this time/cell.
        // However, standard Dijkstra relaxation handles this implicitly: if the current state (T, C) is worse than recorded (dist[r][c], colorGrid[r][c]), we skip.
        // Since we only enqueue if we improve time OR improve color at the same time, this check is sufficient:
        if (time > dist[r][c] || (time === dist[r][c] && currentColor < colorGrid[r][c])) {
            continue;
        }


        // Explore neighbors
        for (const [dr, dc] of directions) {
            const r_next = r + dr;
            const c_next = c + dc;

            // Check bounds
            if (r_next < 0 || r_next >= n || c_next < 0 || c_next >= m) {
                continue;
            }

            const t_new = time + 1;
            const c_new = currentColor;

            const d_existing = dist[r_next][c_next];
            const c_existing = colorGrid[r_next][c_next];

            if (t_new < d_existing) {
                // Case 1: Strictly faster arrival time
                dist[r_next][c_next] = t_new;
                colorGrid[r_next][c_next] = c_new;
                pq.enqueue([t_new, -c_new, r_next, c_next]);
            } else if (t_new === d_existing) {
                // Case 2: Same time arrival. Apply tie-breaker (Max Color).
                if (c_new > c_existing) {
                    // New color is higher, update color and re-enqueue to propagate the higher color forward
                    colorGrid[r_next][c_next] = c_new;
                    // We update the state and enqueue, even though time hasn't changed, 
                    // because the color change might lead to a different outcome in subsequent steps.
                    pq.enqueue([t_new, -c_new, r_next, c_next]);
                }
            }
            // Case 3: t_new > d_existing. Do nothing.
        }
    }

    // 3. Return the final color grid
    return colorGrid;
}
