/**
 * Solves the color diffusion problem using a layered multi-source Breadth-First Search (BFS).
 * 
 * @param {number} n Number of rows.
 * @param {number} m Number of columns.
 * @param {number[][]} sources Array of [r, c, color] initial sources.
 * @returns {number[][]} The final color grid.
 */
function solve(n, m, sources) {
    // Initialize Distance grid. -1 means unvisited/uncolored.
    const distance = Array(n).fill(0).map(() => Array(m).fill(-1));
    // Initialize Color grid. 0 means uncolored initially.
    const color = Array(n).fill(0).map(() => Array(m).fill(0));

    // Queue for BFS: stores [r, c]
    let queue = [];

    // Directions: Up, Down, Left, Right
    const dr = [-1, 1, 0, 0];
    const dc = [0, 0, -1, 1];

    // 1. Seeding the sources
    for (const [r, c, colorVal] of sources) {
        distance[r][c] = 0;
        color[r][c] = colorVal;
        queue.push([r, c]);
    }

    // 2. Layered BFS
    while (queue.length > 0) {
        const currentLayerSize = queue.length;
        const nextQueue = [];

        // Map to store potential arrivals for the next time step (T+1)
        // Key: "r,c", Value: Set of colors arriving
        const arrivals = new Map(); 

        // Get the distance T of the current layer. Safe because queue is not empty.
        const T = distance[queue[0][0]];

        // Process current layer (Time T) to find all potential arrivals at T+1
        for (let i = 0; i < currentLayerSize; i++) {
            const [r, c] = queue[i];
            const current_color = color[r][c];

            // Check neighbors
            for (let k = 0; k < 4; k++) {
                const nr = r + dr[k];
                const nc = c + dc[k];

                // Check boundaries and if unvisited (-1)
                if (nr >= 0 && nr < n && nc >= 0 && nc < m && distance[nr][nc] === -1) {
                    const key = `${nr},${nc}`;

                    if (!arrivals.has(key)) {
                        arrivals.set(key, new Set());
                    }
                    // Record the color attempting to arrive at T+1
                    arrivals.get(key).add(current_color);
                }
            }
        }

        // 3. Resolve arrivals for the next layer (Time T+1)
        for (const [key, colorSet] of arrivals.entries()) {
            const [r_next, c_next] = key.split(',').map(Number);

            // Find the maximum color among simultaneous arrivals
            let maxColor = 0;
            for (const colorVal of colorSet) {
                if (colorVal > maxColor) {
                    maxColor = colorVal;
                }
            }

            // Update grid state for the next layer
            distance[r_next][c_next] = T + 1;
            color[r_next][c_next] = maxColor;
            nextQueue.push([r_next, c_next]);
        }

        queue = nextQueue;
    }

    // 4. Return the final color grid
    return color;
}
