/**
 * MinPriorityQueue implementation for Dijkstra's algorithm.
 * Stores elements prioritized by [time, -color]. Lower time is better. If times are equal, higher color is better (smaller negative color).
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    // Comparison function: compares element A and element B
    // Returns true if A has higher priority (should come before) B
    // Priority is determined by (time, -color) lexicographically.
    compare(a, b) {
        // a and b are [time, neg_color, r, c]
        if (a[0] !== b[0]) {
            // Smaller time wins
            return a[0] < b[0];
        }
        // If times are equal, smaller neg_color wins (i.e., larger color wins)
        return a[1] < b[1];
    }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    getParentIndex(i) {
        return Math.floor((i - 1) / 2);
    }

    getLeftChildIndex(i) {
        return 2 * i + 1;
    }

    getRightChildIndex(i) {
        return 2 * i + 2;
    }

    siftUp(i) {
        let parent = this.getParentIndex(i);
        while (i > 0 && this.compare(this.heap[i], this.heap[parent])) {
            this.swap(i, parent);
            i = parent;
            parent = this.getParentIndex(i);
        }
    }

    siftDown(i) {
        let minIndex = i;
        const size = this.heap.length;

        while (true) {
            let left = this.getLeftChildIndex(i);
            let right = this.getRightChildIndex(i);

            // Check left child
            if (left < size && this.compare(this.heap[left], this.heap[minIndex])) {
                minIndex = left;
            }

            // Check right child
            if (right < size && this.compare(this.heap[right], this.heap[minIndex])) {
                minIndex = right;
            }

            if (minIndex !== i) {
                this.swap(i, minIndex);
                i = minIndex;
            } else {
                break;
            }
        }
    }

    enqueue(element) {
        this.heap.push(element);
        this.siftUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const top = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.siftDown(0);
        return top;
    }
}


