function solve(n, m, sources) {
    const NM = n * m;

    // T[i]: Minimum time to reach cell i (1D index)
    const T = new Array(NM).fill(Infinity);
    // C[i]: Final color of cell i
    const C = new Array(NM).fill(0);

    // Queue for BFS: stores 1D indices. Using array as a queue with a head pointer.
    const queue = [];

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    // 1. Initialization (Multi-source setup)
    for (const source of sources) {
        const r = source[0];
        const c = source[1];
        const color = source[2];

        const idx = r * m + c;

        T[idx] = 0;
        C[idx] = color;
        queue.push(idx);
    }

    let head = 0;

    // 2. BFS Simulation
    while (head < queue.length) {
        const idx = queue[head++];

        const r = Math.floor(idx / m);
        const c = idx % m;

        const t = T[idx];
        const c_current = C[idx];

        for (const [dr, dc] of directions) {
            const r_prime = r + dr;
            const c_prime = c + dc;

            // Check bounds
            if (r_prime >= 0 && r_prime < n && c_prime >= 0 && c_prime < m) {
                const idx_prime = r_prime * m + c_prime;
                const t_prime = t + 1;

