        // Sources are guaranteed to be unique, so no conflict check needed here.
        T[idx] = 0;
        C[idx] = color;
        queue.push(idx);
    }

    let head = 0;

    // 2. BFS Loop
    while (head < queue.length) {
        const idx = queue[head++];

        const r = Math.floor(idx / m);
        const c = idx % m;

        const t = T[idx];
        const c_current = C[idx];

        for (const [dr, dc] of directions) {
