                    // Given the structure, T[idx_prime] should only decrease if it was Infinity, or if we fundamentally change the BFS structure.

                    // Since we only enqueue if T[idx'] = Infinity OR T[idx'] = t', 
                    // we handle the first visit (T[idx'] = Infinity) below.

                } else if (t_prime < T[idx_prime]) {
                    // Strictly faster path found (should only happen if T[idx'] was Infinity)
                    T[idx_prime] = t_prime;
                    C[idx_prime] = c_current;
                    queue.push(idx_prime);
                } else if (t_prime === T[idx_prime]) {
                    // Simultaneous arrival at minimum time
                    if (c_current > C[idx_prime]) {
                        // Update color to the maximum found so far at this minimum time
                        C[idx_prime] = c_current;

                        // Since the color increased at the established minimum time, 
                        // this stronger color must propagate further. Re-enqueue the cell.
                        queue.push(idx_prime);
                    }
