class MinPriorityQueue {
    constructor() {
        // Heap array stores [time, color, r, c]
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    _getParentIndex(i) { return Math.floor((i - 1) / 2); }
    _getLeftChildIndex(i) { return 2 * i + 1; }
    _getRightChildIndex(i) { return 2 * i + 2; }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _compare(a, b) {
        // Primary comparison: time (smaller is higher priority)
        if (a[0] !== b[0]) {
            return a[0] - b[0];
        }
        // Secondary comparison (optional, but good for stability/tie-breaking): color (larger is usually better, but for PQ structure, we stick to time priority)
        return 0; 
    }

    enqueue(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }

    _bubbleUp(index) {
        while (index > 0) {
            const parentIndex = this._getParentIndex(index);
            if (this._compare(this.heap[index], this.heap[parentIndex]) < 0) {
                this._swap(index, parentIndex);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        let minIndex = index;
        const n = this.heap.length;

        while (true) {
            const left = this._getLeftChildIndex(index);
            const right = this._getRightChildIndex(index);

            // Compare with left child
            if (left < n && this._compare(this.heap[left], this.heap[minIndex]) < 0) {
                minIndex = left;
            }

            // Compare with right child
            if (right < n && this._compare(this.heap[right], this.heap[minIndex]) < 0) {
                minIndex = right;
            }

            if (minIndex !== index) {
                this._swap(index, minIndex);
                index = minIndex;
            } else {
                break;
            }
        }
    }
}


