/**
 * Helper class for MinHeap implementation.
 * Stores elements as [time, color, r, c] and prioritizes by time.
 */
class MinPriorityQueue {
    constructor() {
        // Heap array stores [time, color, r, c]
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    _getParentIndex(i) { return Math.floor((i - 1) / 2); }
    _getLeftChildIndex(i) { return 2 * i + 1; }
    _getRightChildIndex(i) { return 2 * i + 2; }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _compare(a, b) {
        // Primary comparison: time (smaller is higher priority)
        if (a[0] !== b[0]) {
            return a[0] - b[0];
        }
        // Secondary comparison (optional, but good for stability/tie-breaking): color (larger is usually better, but for PQ structure, we stick to time priority)
        return 0; 
    }

    enqueue(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }

    _bubbleUp(index) {
        while (index > 0) {
            const parentIndex = this._getParentIndex(index);
            if (this._compare(this.heap[index], this.heap[parentIndex]) < 0) {
                this._swap(index, parentIndex);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        let minIndex = index;
        const n = this.heap.length;

        while (true) {
            const left = this._getLeftChildIndex(index);
            const right = this._getRightChildIndex(index);

            // Compare with left child
            if (left < n && this._compare(this.heap[left], this.heap[minIndex]) < 0) {
                minIndex = left;
            }

            // Compare with right child
            if (right < n && this._compare(this.heap[right], this.heap[minIndex]) < 0) {
                minIndex = right;
            }

            if (minIndex !== index) {
                this._swap(index, minIndex);
                index = minIndex;
            } else {
                break;
            }
        }
    }
}


function solve(n, m, sources) {
    // Initialize distance matrix (Time) and final color matrix
    // Using a large number for infinity since NM <= 10^5, max time is less than NM
    const INF = n * m + 1;
    const dist = Array(n).fill(0).map(() => Array(m).fill(INF));
    const finalColor = Array(n).fill(0).map(() => Array(m).fill(0));

    // Priority Queue: stores [time, color, r, c]
    const pq = new MinPriorityQueue();

    // 1. Seed the sources
    for (const source of sources) {
        const [r, c, color] = source;

        // Check for duplicates in sources array based on coordinates (though problem states they are unique)
        if (dist[r][c] > 0) {
            dist[r][c] = 0;
            finalColor[r][c] = color;
            // Push initial state: [Time=0, Color, R, C]
            pq.enqueue([0, color, r, c]);
        }
    }

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    // 2. BFS/Dijkstra execution
    while (!pq.isEmpty()) {
        const [t, color, r, c] = pq.dequeue();

        // Check for outdated entry based on time AND color
        // If we found a path with the same minimum time but a higher color earlier, we should skip this older/inferior entry.
        if (t > dist[r][c] || (t === dist[r][c] && color < finalColor[r][c])) {
             continue;
        }

        // Propagate to neighbors
        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            // Check bounds
            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const t_new = t + 1;
                const c_new = color;

                const t_old = dist[nr][nc];
                const c_old = finalColor[nr][nc];

                // Case 1: Faster arrival found
                if (t_new < t_old) {
                    dist[nr][nc] = t_new;
                    finalColor[nr][nc] = c_new;
                    pq.enqueue([t_new, c_new, nr, nc]);
                } 
                // Case 2: Same arrival time
                else if (t_new === t_old) {
                    // Tie-breaker: Max color wins
                    if (c_new > c_old) {
                        finalColor[nr][nc] = c_new;
                        // IMPORTANT: Since the color improved at the same minimum time, 
                        // we must re-enqueue this cell to propagate the higher color influence.
                        pq.enqueue([t_new, c_new, nr, nc]);
                    }
                }
                // Case 3: Slower arrival (t_new > t_old), skip.
            }
        }
    }

    return finalColor;
}
